import React, { createContext, useContext, useState, useEffect } from 'react';
import { adminSignIn } from '../utils/api';

// ─────────────────────────────────────────────────────────────────────────────
// AuthContext — wraps entire app, gives login/logout/admin to every page
//
// YOUR BACKEND: POST /Admin/SignIn → { Status:"OK", Result:{ Name, Email, ContactNo, Role, _id } }
// ⚠️  Your backend currently does NOT return a JWT token.
//     You need to add this to your signIn route in Node.js (see note below).
// ─────────────────────────────────────────────────────────────────────────────

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [admin, setAdmin]     = useState(null);
  const [loading, setLoading] = useState(true);

  // On app load — restore session if already logged in
  useEffect(() => {
    const savedUser  = localStorage.getItem('fixit_admin_user');
    const savedToken = localStorage.getItem('fixit_admin_token');
    if (savedUser && savedToken) {
      setAdmin(JSON.parse(savedUser));
    }
    setLoading(false);
  }, []);

  // ── LOGIN ──────────────────────────────────────────────────────────────────
  const login = async (Email, Password) => {
    const res = await adminSignIn(Email, Password);

    // Your backend returns: { Status: "OK", Result: { Name, Email, ContactNo, Role, _id } }
    if (res.data.Status !== 'OK') {
      throw new Error(res.data.Result); // "Invalid Email" or "Invalid Password"
    }

    const adminData = res.data.Result;

    // ⚠️  IMPORTANT: Your backend doesn't return a token yet.
    // Add this to your Node.js signIn in AdminRepositories.js:
    //
    //   const jwt = require('jsonwebtoken');
    //   const token = jwt.sign({ _id: admin._id, Role: admin.Role }, process.env.JWT_SECRET, { expiresIn: '7d' });
    //   return { Status: "OK", Result: { Name, Email, ContactNo, Role, _id }, Token: token };
    //
    // Then in AdminController.js signIn:
    //   return res.status(200).json(result);  ← already there, just add Token to Result
    //
    // For now we store admin data without token (works but unprotected):
    const token = res.data.Token || 'temp_no_token';

    localStorage.setItem('fixit_admin_token', token);
    localStorage.setItem('fixit_admin_user', JSON.stringify(adminData));
    setAdmin(adminData);

    return adminData;
  };

  // ── LOGOUT ─────────────────────────────────────────────────────────────────
  const logout = () => {
    localStorage.removeItem('fixit_admin_token');
    localStorage.removeItem('fixit_admin_user');
    setAdmin(null);
  };

  return (
    <AuthContext.Provider value={{ admin, login, logout, loading }}>
      {children}
    </AuthContext.Provider>
  );
}

// Use this hook in any page:  const { admin, login, logout } = useAuth();
export function useAuth() {
  return useContext(AuthContext);
}
